from solution import build_user_purchase_index


def test_preserves_original_behavior_and_filters_minimum_amount():
    events = [
        {"user_id": "alice", "kind": "purchase", "amount": 4},
        {"user_id": "alice", "kind": "purchase", "amount": 9},
        {"user_id": "bob", "kind": "purchase", "amount": 7},
    ]

    assert build_user_purchase_index(events) == {
        "alice": {"count": 2, "total": 13},
        "bob": {"count": 1, "total": 7},
    }
    assert build_user_purchase_index(events, min_amount=8) == {
        "alice": {"count": 1, "total": 9},
    }


def test_rejects_negative_min_amount():
    with pytest.raises(ValueError):
        build_user_purchase_index([], min_amount=-1)

