from __future__ import annotations


def build_user_purchase_index(
    events: list[dict],
    *,
    min_amount: int = 0,
) -> dict[str, dict[str, int]]:
    if min_amount < 0:
        raise ValueError("min_amount must be non-negative")

    index: dict[str, dict[str, int]] = {}
    for event in events:
        user_id = event.get("user_id")
        amount = event.get("amount")
        if event.get("kind") != "purchase" or not isinstance(user_id, str) or not user_id:
            continue
        if not isinstance(amount, int) or amount < min_amount:
            continue

        bucket = index.setdefault(user_id, {"count": 0, "total": 0})
        bucket["count"] += 1
        bucket["total"] += amount
    return index

